import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useYcmhListFilterState } from '../../../hooks/useYcmhListFilterState';
import { useYcmhPermissions } from '../../../hooks/useYcmhPermissions';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { PurchaseRequestDto } from '../../../services/mh/models';
import { PR_STATUS_OPTIONS, PAGE_SIZE } from '../../../utils/constants';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { ycmhPageLabels } from '../../../constants/ycmhPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { WmsSchemaListGrid } from '../../../components/list/WmsSchemaListGrid';
import { buildPurchasingListToolbar } from '../../../features/mh/purchasingListToolbar';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../../../components/list/VoucherListPagination';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-mh-ycmh';
const PAGE_ID = 'mh-ycmh';

const YcmhListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { canCreate, canApprove, canWrite } = useYcmhPermissions();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useYcmhListFilterState(LIST_FILTER_SCOPE.ycmh);

  const [items, setItems] = useState<PurchaseRequestDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSize] = useState<VoucherListPageSize>(DEFAULT_VOUCHER_LIST_PAGE_SIZE);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });

  const refresh = useCallback(() => {
    setReloadKey(k => k + 1);
    selection.clearActiveRow();
  }, [selection]);

  const handleSearch = useCallback(() => {
    setSearch(searchDraft.trim());
    resetPage();
    selection.clearActiveRow();
  }, [searchDraft, setSearch, resetPage, selection]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const activeRow = selection.activeRow;

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getRequests({
        status: status || undefined,
        fromDate: fromDate ? `${fromDate}T00:00:00.000Z` : undefined,
        toDate: toDate ? `${toDate}T23:59:59.999Z` : undefined,
        search: search || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (cancelled) return;
          setItems(res.items);
          setTotalCount(res.totalCount);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, ycmhPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, status, fromDate, toDate, page, pageSize, search, dispatch, reloadKey]);

  const handleApprove = useCallback(async (id: string) => {
    try {
      await purchasingService.approveRequest(id);
      dispatchAppToast(dispatch, { message: ycmhPageLabels.approveSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, ycmhPageLabels.approveError),
        type: 'error',
      });
    }
  }, [dispatch, refresh]);

  const navigateToRow = useCallback((id: string, edit?: boolean) => {
    if (edit) navigate(`/mh/ycmh/them?editId=${id}`);
    else navigate(`/mh/ycmh/${id}`);
  }, [navigate]);

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow?.status === 'Draft' && canWrite;
  const canApproveActive = activeRow?.status === 'PendingApproval' && canApprove;

  const toolbarProps = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      profile: 'voucher' as const,
      actions: buildPurchasingListToolbar({
        testIdPrefix: TEST_ID,
        onRefresh: refresh,
        onEditConfig: () => setShowSchemaEditor(true),
        canCreate,
        onCreate: () => navigate('/mh/ycmh/them'),
        canView: canViewActive,
        onView: () => activeRow && navigateToRow(activeRow.id),
        canEdit: canEditActive,
        onEdit: () => activeRow && navigateToRow(activeRow.id, true),
        canApprove: canApproveActive,
        onApprove: () => activeRow && handleApprove(activeRow.id),
      }),
    }),
    [
      refresh,
      canCreate,
      canViewActive,
      canEditActive,
      canApproveActive,
      activeRow,
      navigate,
      navigateToRow,
      handleApprove,
    ],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            placeholder="Số YCMH, phòng ban, mô tả…"
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => { setStatus(e.target.value); resetPage(); }}
            options={PR_STATUS_OPTIONS}
            fullWidth
            data-testid={`${TEST_ID}-filter-status`}
          />
        ),
      },
    ],
    [
      fromDate,
      toDate,
      datePreset,
      searchDraft,
      status,
      applyDateRange,
      resetPage,
      setSearchDraft,
      handleSearch,
      setStatus,
    ],
  );

  const listBody = (
    <WmsSchemaListGrid
      catalogKind={LIST_UI_SCHEMA_KIND.purchaseRequest}
      testIdPrefix={TEST_ID}
      rows={items}
      page={page}
      pageSize={pageSize}
      showTableLoading={showTableLoading}
      emptyLabel={ycmhPageLabels.empty}
      selection={selection}
      onRowDoubleClick={r => navigateToRow(r.id)}
    />
  );

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: ycmhPageLabels.listTitle,
          titleIconClass: 'fas fa-file-invoice',
          pageId: PAGE_ID,
        }}
        toolbarProps={toolbarProps}
        listTitle={ycmhPageLabels.listSubtitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={6}
        footer={(
          <VoucherListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearActiveRow(); }}
            onPageSizeChange={size => {
              setPageSize(size as VoucherListPageSize);
              setPage(1);
              selection.clearActiveRow();
            }}
          />
        )}
        modals={(
          <ListUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={LIST_UI_SCHEMA_KIND.purchaseRequest}
            isOpen={showSchemaEditor}
            onClose={() => setShowSchemaEditor(false)}
            title="Cấu hình hiển thị danh sách"
            onSaved={() => { setReloadKey(k => k + 1); }}
          />
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default YcmhListPage;
